    const tk = keyMap[k] || k;
    if (slice[tk] !== payload[k]) {
        slice[tk] = payload[k];
        changed = true;
    }
}

if (!changed) return null;
flow.set('slice' + letter, slice);

// Output 1: trigger active-slice recompute (same as before)
// Output 2: full snapshot of all 4 slices for the new display widget
const allSlices = ['A','B','C','D'].map(L => ({
    letter: L, ...(flow.get('slice'+L) || {})
}));
const summary = { slices: allSlices, updated: letter };

return [
    { topic: msg.topic, payload: slice, slice: letter, sliceIndex: idx },
    { payload: summary }
];

const empty = { payload: '' };
const zero  = { payload: 0 };
node.send([
    { ...empty },   // Logged in Client Name
    { ...zero  },   // SWR Linear
    { payload: { slices: [] } }  // Slice Display
]);
return null;
